#include<bits/stdc++.h>
using namespace std;
const int K = (1<<12)+5 , mod = 1e8;
int n,m,a[20],dp[20][K],ans;bool is[K];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            int x;cin>>x;
            if(x)a[i]|=(1<<j-1);
        }
    for(int s=0;s<(1<<m);s++){
        is[s]=(!(s&(s<<1)))&(!(s&(s>>1)));
        if(is[s]&&(s&a[1])==s)dp[1][s]=1;
    }
    for(int i=2;i<=n;i++)for(int s=0;s<(1<<m);s++)
        if((s&a[i-1])==s&&is[s])for(int j=0;j<(1<<m);j++)
            if((j&a[i])==j&&is[j]&&!(s&j))dp[i][j]=(dp[i][j]+dp[i-1][s])%mod;
    for(int s=0;s<(1<<m);s++)ans=(ans+dp[n][s])%mod;
    cout<<ans<<"\n";
    return 0;
}
